#include <stdio.h>
#include <string.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char s[100001];
        scanf("%s", s);
        int count0 = 0, count1 = 0;
        for (int i = 0; i < strlen(s); i++) {
            if (s[i] == '0') count0++;
            else count1++;
        }
        if (count0 == 1 || count1 == 1) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

code.C++:
#include <iostream>
#include <string>
using namespace std;
int main() {
    int T;
    cin >> T;
    while (T--) {
        string s;
        cin >> s;
        int count0 = 0, count1 = 0;
        for (char c : s) {
            if (c == '0') count0++;
            else count1++;
        }
        if (count0 == 1 || count1 == 1) cout << "Yes" << endl;
        else cout << "No" << endl;
    }
    return 0;
}

code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String s = sc.next();
            int count0 = 0, count1 = 0;
            for (char c : s.toCharArray()) {
                if (c == '0') count0++;
                else count1++;
            }
            if (count0 == 1 || count1 == 1) System.out.println("Yes");
            else System.out.println("No");
        }
    }
}

