    const s = readline();
    let count0 = 0, count1 = 0;
    for (let j = 0; j < s.length; j++) {
        if (s[j] === '0') count0++;
        else count1++;
    }
    if (count0 === 1 || count1 === 1) console.log('Yes');
    else console.log('No');
}

